<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #2c3e50;
            --taskbar-bg: rgba(40, 40, 40, 0.9);
            --window-bg: #f0f0f0;
            --titlebar-bg: #333;
            --accent-color: #e95420; /* Ubuntu Orange */
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body, html {
            height: 100%;
            overflow: hidden;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #2c3e50 0%, #000000 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 0;
            width: 100%;
            height: 50px;
            background: var(--taskbar-bg);
            display: flex;
            align-items: center;
            padding: 0 10px;
            gap: 15px;
            border-top: 1px solid #444;
            z-index: 9999;
        }

        .launcher {
            padding: 8px 15px;
            background: #555;
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            transition: background 0.2s;
        }

        .launcher:hover {
            background: var(--accent-color);
        }

        /* Windows */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none; /* Hidden by default */
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #999;
        }

        .titlebar {
            background: var(--titlebar-bg);
            color: white;
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            user-select: none;
        }

        .win-close {
            background: #ff5f56;
            border: none;
            color: white;
            border-radius: 50%;
            width: 20px;
            height: 20px;
            cursor: pointer;
            font-size: 12px;
            line-height: 1;
        }

        .window-content {
            flex: 1;
            padding: 15px;
            overflow: auto;
        }

        /* Files App Styles */
        #files-path {
            margin-bottom: 10px;
            font-weight: bold;
            color: #666;
            font-size: 0.9em;
        }

        .fs-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
            gap: 15px;
        }

        .fs-item {
            padding: 10px;
            text-align: center;
            cursor: pointer;
            border-radius: 4px;
            transition: background 0.2s;
        }

        .fs-item:hover {
            background: #ddd;
        }

        #files-up {
            margin-bottom: 15px;
            padding: 5px 10px;
            cursor: pointer;
        }

        /* Notepad App Styles */
        #tabs {
            display: flex;
            background: #ddd;
            border-bottom: 1px solid #ccc;
        }

        .tab {
            padding: 8px 15px;
            cursor: pointer;
            border-right: 1px solid #ccc;
            background: #eee;
            font-size: 0.9em;
            max-width: 120px;
            overflow: hidden;
            white-space: nowrap;
            text-overflow: ellipsis;
        }

        .tab.active {
            background: var(--window-bg);
            border-bottom: 2px solid var(--accent-color);
            font-weight: bold;
        }

        #editor {
            width: 100%;
            height: calc(100% - 40px);
            resize: none;
            border: none;
            padding: 10px;
            font-family: 'Courier New', Courier, monospace;
            outline: none;
        }

        #new-tab {
            margin-left: 5px;
            padding: 2px 8px;
            cursor: pointer;
        }
    </style>
</head>
<body>

<div id="desktop">
    <!-- Files Window -->
    <div id="files-window" class="window" style="top: 100px; left: 100px;">
        <div class="titlebar">
            <span>File Explorer</span>
            <button class="win-close">✕</button>
        </div>
        <div class="window-content">
            <button id="files-up">.. (Up)</button>
            <div id="files-path">/</div>
            <div id="files-list" class="fs-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window" style="top: 150px; left: 450px;">
        <div class="titlebar">
            <span>Notepad</span>
            <button class="win-close">✕</button>
        </div>
        <div id="tabs"></div>
        <div class="window-content" style="padding: 0;">
            <textarea id="editor"></textarea>
        </div>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files" class="launcher">Files</button>
        <button id="open-notepad" class="launcher">Notepad</button>
    </div>
</div>

<script>
    /** --- Filesystem Data & Logic --- **/
    const fsData = {
        "root": {
            "bin": {},
            "etc": {},
            "home": {
                "user": {
                    "Documents": {},
                    "Downloads": {},
                    "Pictures": {}
                }
            },
            "usr": {},
            "var": {}
        }
    };

    let currentPath = ["root"]; // "root" is internal, we map it to "/" for display

    function renderFiles() {
        const listEl = document.getElementById('files-list');
        const pathEl = document.getElementById('files-path');
        listEl.innerHTML = '';

        // Calculate current directory object
        let currentDir = fsData["root"];
        for (let i = 1; i < currentPath.length; i++) {
            currentDir = currentDir[currentPath[i]];
        }

        // Update path display
        const displayPath = currentPath.map(p => p === "root" ? "/" : p).join("/");
        pathEl.innerText = displayPath;

        // Render items
        Object.keys(currentDir).forEach(key => {
            const item = document.createElement('div');
            item.className = 'fs-item';
            item.innerText = key;
            item.ondblclick = () => {
                if (typeof currentDir[key] === 'object' && !Array.isArray(currentDir[key])) {
                    currentPath.push(key);
                    renderFiles();
                }
            };
            listEl.appendChild(item);
        });
    }

    document.getElementById('files-up').onclick = () => {
        if (currentPath.length > 1) {
            currentPath.pop();
            renderFiles();
        }
    };

    /** --- Notepad Logic --- **/
    let tabs = JSON.parse(localStorage.getItem('notepad_tabs')) || [
        { id: Date.now(), title: 'Untitled', content: '' }
    ];
    let activeTabId = tabs[0].id;

    const tabsContainer = document.getElementById('tabs');
    const editor = document.getElementById('editor');

    function saveNotepad() {
        localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
    }

    function renderTabs() {
        tabsContainer.innerHTML = '';
        tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            tabEl.innerText = tab.title;
            tabEl.onclick = () => {
                activeTabId = tab.id;
                renderTabs();
                updateEditorContent();
            };
            tabsContainer.appendChild(tabEl);
        });

        const newBtn = document.createElement('button');
        newBtn.id = 'new-tab';
        newBtn.innerText = '+';
        newBtn.onclick = createNewTab;
        tabsContainer.appendChild(newBtn);
    }

    function updateEditorContent() {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) editor.value = activeTab.content;
    }

    function createNewTab() {
        const newId = Date.now();
        tabs.push({ id: newId, title: 'New Tab', content: '' });
        activeTabId = newId;
        renderTabs();
        updateEditorContent();
        saveNotepad();
    }

    editor.oninput = () => {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
            activeTab.content = editor.value;
            saveNotepad();
        }
    };

    /** --- Window Management & Draggability --- **/
    function toggleWindow(id, show) {
        const win = document.getElementById(id);
        win.style.display = show ? 'flex' : 'none';
        if (show && id === 'notepad-window') {
            renderTabs();
            updateEditorContent();
        }
    }

    document.getElementById('open-files').onclick = () => {
        currentPath = ["root"];
        renderFiles();
        toggleWindow('files-window', true);
    };

    document.getElementById('open-notepad').onclick = () => {
        toggleWindow('notepad-window', true);
    };

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.onclick = (e) => {
            const win = e.target.closest('.window');
            toggleWindow(win.id, false);
        };
    });

    // Draggable Logic
    document.querySelectorAll('.titlebar').forEach(bar => {
        let isDragging = false;
        let offsetX, offsetY;

        bar.onmousedown = (e) => {
            isDragging = true;
            const win = bar.closest('.window');
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            win.style.zIndex = 1000; // Bring to front
        };

        document.onmousemove = (e) => {
            if (!isDragging) return;
            const win = bar.closest('.window');
            win.style.left = (e.clientX - offsetX) + 'px';
            win.style.top = (e.clientY - offsetY) + 'px';
        };

        document.onmouseup = () => {
            isDragging = false;
        };
    });

    // Initial Load
    renderFiles();
</script>

</body>
</html>
